const fetch = require('node-fetch');

const rawBaseUrl = String($baseUrl || 'http://localhost:4321');
const baseUrl = rawBaseUrl.endsWith('/') ? rawBaseUrl.slice(0, -1) : rawBaseUrl;
const endpoint = baseUrl + '/api/workpaper/n8n/forecast';
const sheetName = $sheetName || 'Inputs';
const address = String($address || 'B3').toUpperCase();
const rawValue = $valueJson === undefined || $valueJson === '' ? '0.4' : String($valueJson);

let value;
try {
  value = JSON.parse(rawValue);
} catch (_error) {
  const numeric = Number(rawValue);
  value = Number.isFinite(numeric) ? numeric : rawValue;
}

const response = await fetch(endpoint, {
  method: 'POST',
  headers: {
    'content-type': 'application/json',
    accept: 'application/json'
  },
  body: JSON.stringify({ sheetName, address, value })
});

const text = await response.text();
if (!response.ok) {
  throw new Error('Bilig WorkPaper request failed with HTTP ' + response.status + ': ' + text);
}

const proof = JSON.parse(text);
if (proof.verified !== true) {
  throw new Error('Bilig WorkPaper did not verify the edit: ' + text);
}

if (!proof.checks?.formulasPersisted || !proof.checks?.restoredMatchesAfter || !proof.checks?.computedOutputChanged) {
  throw new Error('Bilig formula proof checks failed: ' + JSON.stringify(proof.checks));
}

return JSON.stringify({
  verified: true,
  editedCell: proof.editedCell,
  beforeExpectedArr: proof.before?.expectedArr,
  afterExpectedArr: proof.after?.expectedArr,
  targetGap: proof.after?.targetGap,
  checks: proof.checks,
  github: 'https://github.com/proompteng/bilig'
}, null, 2);
